mapper.update:
UPDATE collection
SET title       = #{title},
    description = #{description},
    is_public   = #{isPublic}
WHERE collection_id = #{collectionId}
  AND mid = #{mid}

mapper.delete:
DELETE FROM collection
WHERE collection_id = #{collectionId}
  AND mid = #{mid}

DELETE FROM collection_movie
WHERE collection_id = #{collectionId}
  AND movie_id = #{movieId}

mapper.select:
SELECT COUNT(*)
FROM collection_movie
WHERE collection_id = #{collectionId}
  AND movie_id = #{movieId}
